Span<nint> a = stackalloc nint[] { 1, 2, 3, 4, 5 };
Console.WriteLine($"Length: {a.Length}, Element size: {sizeof(nint)} bytes");

nint sum = 0;
for (int i = 0; i < a.Length; i++)
{
    Console.WriteLine($"  a[{i}] = {a[i]}");
    sum += a[i];
}
Console.WriteLine($"Sum: {sum}");

// Also test nuint (unsigned native int)
Span<nuint> b = stackalloc nuint[3];
b[0] = 10;
b[1] = 20;
b[2] = 30;
Console.WriteLine($"\nnuint span length: {b.Length}, sum: {b[0] + b[1] + b[2]}");

